		String defCtx = cfg.defaultContextString;
		int sampleMin = cfg.churnSampleMin;
		int sampleMax = cfg.churnSampleMax;
		double samplePct = cfg.churnSamplePercent;
		double churnReaddTh = cfg.churnReaddThreshold;
		double churnRemovalTh = cfg.churnRemovalRatioThreshold;
		boolean roundEst = cfg.roundJoinEstimates;
		long estimateCacheSeconds = cfg.estimateCacheSeconds;
		int zeroIntersectionExactLimit = cfg.zeroIntersectionExactDistinctLimit;
		double zeroIntersectionSkew = cfg.zeroIntersectionSkewRatio;
		long zeroIntersectionBudget = cfg.zeroIntersectionRowBudget;
		int zeroIntersectionSampleSize = cfg.zeroIntersectionSampleSize;
		int queueInitialLimit = cfg.incrementalQueueInitialLimit;
		long queueIdleResetMillis = cfg.incrementalQueueIdleResetMillis;
		long queueEstimatedStatementBytes = cfg.incrementalQueueEstimatedStatementBytes;
		int memoryMonitorCheckInterval = cfg.memoryMonitorCheckInterval;
		long memoryMonitorEstimatedOperationBytes = cfg.memoryMonitorEstimatedOperationBytes;

		// Overlay from system properties (take precedence)
		sketchNominalEntries = propInt("nominalEntries", sketchNominalEntries);
		sBuckets = propInt("subjectBucketCount", sBuckets);
		pBuckets = propInt("predicateBucketCount", pBuckets);
		oBuckets = propInt("objectBucketCount", oBuckets);
		cBuckets = propInt("contextBucketCount", cBuckets);
		contextPairSketches = propBool("contextPairSketchesEnabled", contextPairSketches);
		thrEvery = propLong("throttleEveryN", thrEvery);
		thrMs = propLong("throttleMillis", thrMs);
		refreshMs = propLong("refreshSleepMillis", refreshMs);
		defCtx = propString("defaultContextString", defCtx);
		sampleMin = propInt("churnSampleMin", sampleMin);
		sampleMax = propInt("churnSampleMax", sampleMax);
		samplePct = propDouble("churnSamplePercent", samplePct);
		churnReaddTh = propDouble("churnReaddThreshold", churnReaddTh);
		churnRemovalTh = propDouble("churnRemovalRatioThreshold", churnRemovalTh);
		roundEst = propBool("roundJoinEstimates", roundEst);
		estimateCacheSeconds = propLong(ESTIMATE_CACHE_SECONDS_PROPERTY, estimateCacheSeconds);
		zeroIntersectionExactLimit = propInt(ZERO_INTERSECTION_EXACT_DISTINCT_LIMIT_PROPERTY,
				zeroIntersectionExactLimit);
		zeroIntersectionSkew = propDouble(ZERO_INTERSECTION_SKEW_RATIO_PROPERTY, zeroIntersectionSkew);
		zeroIntersectionBudget = propLong(ZERO_INTERSECTION_ROW_BUDGET_PROPERTY, zeroIntersectionBudget);
		zeroIntersectionSampleSize = propInt(ZERO_INTERSECTION_SAMPLE_SIZE_PROPERTY, zeroIntersectionSampleSize);
		queueInitialLimit = propInt("incrementalQueueInitialLimit", queueInitialLimit);
		queueIdleResetMillis = propLong("incrementalQueueIdleResetMillis", queueIdleResetMillis);
		queueEstimatedStatementBytes = propLong("incrementalQueueEstimatedStatementBytes",
				queueEstimatedStatementBytes);
		memoryMonitorCheckInterval = propInt("memoryMonitorCheckInterval", memoryMonitorCheckInterval);
		memoryMonitorEstimatedOperationBytes = propLong("memoryMonitorEstimatedOperationBytes",
				memoryMonitorEstimatedOperationBytes);
		if (!propPresent("memoryMonitorEstimatedOperationBytes")
				&& propPresent("incrementalQueueEstimatedStatementBytes")) {
			memoryMonitorEstimatedOperationBytes = queueEstimatedStatementBytes;
		}

		sketchNominalEntries = Math.max(16, sketchNominalEntries);
		samplePct = clamp(samplePct, 0.0, 1.0);
		sampleMin = Math.max(0, sampleMin);
		sampleMax = Math.max(0, sampleMax);
		churnReaddTh = clamp(churnReaddTh, 0.0, 1.0);
		churnRemovalTh = clamp(churnRemovalTh, 0.0, 1.0);
		estimateCacheSeconds = Math.max(0L, estimateCacheSeconds);
		zeroIntersectionExactLimit = Math.max(0, zeroIntersectionExactLimit);
		zeroIntersectionSkew = Math.max(0.0d, zeroIntersectionSkew);
		zeroIntersectionBudget = Math.max(0L, zeroIntersectionBudget);
		zeroIntersectionSampleSize = Math.max(0, zeroIntersectionSampleSize);
		queueInitialLimit = Math.clamp(queueInitialLimit, 1, INCREMENTAL_QUEUE_MAX_LIMIT);
		queueIdleResetMillis = Math.max(1L, queueIdleResetMillis);
		queueEstimatedStatementBytes = Math.max(1L, queueEstimatedStatementBytes);
		memoryMonitorCheckInterval = Math.max(1, memoryMonitorCheckInterval);
		memoryMonitorEstimatedOperationBytes = Math.max(1L, memoryMonitorEstimatedOperationBytes);

		this.statementSource = Objects.requireNonNull(statementSource, "statementSource");
		this.maxBucketCount = maxBucketCount(sBuckets, pBuckets, oBuckets, cBuckets);
		this.subjectBucketCount = sBuckets;
		this.predicateBucketCount = pBuckets;
		this.objectBucketCount = oBuckets;
		this.contextBucketCount = cBuckets;
		this.contextPairSketchesEnabled = contextPairSketches;
